class Solution:
    def maximumLength(self, s: str) -> int:
        from collections import defaultdict

        # Dictionary to store counts of special substrings
        count = defaultdict(int)

        # Iterate through all possible substrings
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n + 1):
                substr = s[i:j]
                # Check if the substring is special (all same characters)
                if all(c == substr[0] for c in substr):
                    count[substr] += 1

        # Find the maximum length of a special substring that appears at least three times
        max_len = -1
        for substr, freq in count.items():
            if freq >= 3:
                max_len = max(max_len, len(substr))

        return max_len
